// ============================================================
// INPUT — correct node names
// ============================================================

const agentOutput  = $('AI Agent: Reply Costumer').first().json;
const preparedData = $('Code: Prepare Data For AI Agent').first().json;

// ============================================================
// STEP 1: Extract reply text
// ============================================================

let replyText = agentOutput?.output ?? null;

if (!replyText || replyText.trim() === '') {
  replyText = "Sorry, I couldn't process your request at the moment. Please try again! 😊";
}

replyText = replyText.trim();

// ============================================================
// STEP 2: Split into Messenger bubbles (2000 char limit)
// ============================================================

const MAX_LENGTH = 2000;
const bubbles = [];

if (replyText.length <= MAX_LENGTH) {
  bubbles.push(replyText);
} else {
  const paragraphs = replyText.split(/\n\n+/);
  let currentBubble = '';

  for (const paragraph of paragraphs) {
    const joined = currentBubble ? currentBubble + '\n\n' + paragraph : paragraph;
    if (joined.length <= MAX_LENGTH) {
      currentBubble = joined;
    } else {
      if (currentBubble) bubbles.push(currentBubble.trim());
      currentBubble = paragraph;
    }
  }
  if (currentBubble) bubbles.push(currentBubble.trim());
}

// ============================================================
// STEP 3: Return everything downstream needs
// ============================================================

return [{
  json: {
    reply_text:       replyText,
    reply_bubbles:    bubbles,
    bubble_count:     bubbles.length,
    needs_splitting:  bubbles.length > 1,
    sender_id:        preparedData.sender_id,
    page_token:       preparedData.page_token,
    page_id:          preparedData.page_id,
    message_content:  preparedData.message_content,
    message_type:     preparedData.message_type,
    conversation_id:  preparedData.conversation_id ?? null,
  }
}];

// ============================================================
// INPUT: Get raw data from previous nodes
// ============================================================

const webhookData = $('Recieve Meta Data').first().json.body;
const messaging = webhookData.entry?.[0]?.messaging?.[0];

// Client credentials — correct node name
const clientData = $('Postgres: Fetch Client').first().json;

// History comes directly as a string from $input (Postgres: Get History output)
const historyRaw = $input.first().json.history ?? '';

// ============================================================
// Gemini nodes — safe access (only ran in specific branches)
// ============================================================

let audioTranscript = null;
try {
  const audioItems = $('Gemini: Transcribe Audio').all();
  if (audioItems && audioItems.length > 0) {
    audioTranscript = audioItems[0].json?.candidates?.[0]?.content?.parts?.[0]?.text ?? null;
  }
} catch (e) {
  audioTranscript = null;
}

let imageDescription = null;
try {
  const imageItems = $('Gemini: Analyze Image').all();
  if (imageItems && imageItems.length > 0) {
    imageDescription = imageItems[0].json?.candidates?.[0]?.content?.parts?.[0]?.text ?? null;
  }
} catch (e) {
  imageDescription = null;
}

// ============================================================
// STEP 1: Determine message type
// ============================================================

let messageType = 'unknown';
let messageContent = '';

const textMessage = messaging?.message?.text;
const attachments = messaging?.message?.attachments;
const stickerId = messaging?.message?.sticker_id;

if (textMessage && textMessage.trim() !== '') {
  messageType = 'text';
  messageContent = textMessage.trim();

} else if (stickerId) {
  // Sticker — stop cleanly
  return [];

} else if (attachments && attachments.length > 0) {
  const attachmentType = attachments[0]?.type;

  if (attachmentType === 'audio') {
    messageType = 'audio';
    messageContent = (audioTranscript && audioTranscript.trim() !== '')
      ? audioTranscript.trim()
      : '[Audio message could not be transcribed]';
    if (!audioTranscript) messageType = 'audio_failed';

  } else if (attachmentType === 'image') {
    messageType = 'image';
    messageContent = (imageDescription && imageDescription.trim() !== '')
      ? `[Image] ${imageDescription.trim()}`
      : '[Customer sent an image but it could not be analyzed]';
    if (!imageDescription) messageType = 'image_failed';

  } else if (attachmentType === 'video') {
    messageType = 'unsupported';
    messageContent = '[Customer sent a video]';

  } else if (attachmentType === 'file') {
    messageType = 'unsupported';
    messageContent = '[Customer sent a file attachment]';

  } else {
    messageType = 'unsupported';
    messageContent = `[Customer sent an unsupported attachment: ${attachmentType}]`;
  }

} else {
  // Read receipts, delivery confirmations, postbacks — ignore
  return [];
}

// ============================================================
// STEP 2: Stop execution for ignored/unknown events
// ============================================================

if (messageType === 'ignored' || messageType === 'unknown' || messageContent === '') {
  return [];
}

// ============================================================
// STEP 3: Build conversation history string
// ============================================================

const history = (historyRaw && historyRaw.trim() !== '')
  ? historyRaw.trim()
  : 'No previous conversation. This is the first message from this customer.';

// ============================================================
// STEP 4: Extract identifiers
// ============================================================

const senderId    = messaging?.sender?.id ?? null;
const pageId      = messaging?.recipient?.id ?? null;
const pageToken   = clientData?.page_token ?? null;
const pageName    = clientData?.page_name ?? 'the store';

// Conversation ID from Merge: Get Conversation ID node
const conversationId = $('Merge: Get Conversation ID').first().json?.id ?? null;

// ============================================================
// STEP 5: Return clean output
// ============================================================

return [{
  json: {
    message_content:  messageContent,
    message_type:     messageType,
    history:          history,
    sender_id:        senderId,
    page_id:          pageId,
    page_token:       pageToken,
    page_name:        pageName,
    conversation_id:  conversationId,
    raw_text:         textMessage ?? null,
    has_attachment:   attachments ? true : false,
    attachment_type:  attachments?.[0]?.type ?? null,
    attachment_url:   attachments?.[0]?.payload?.url ?? null,
  }
}];
